                    /* Keep current inlet and heater state */
                    /* State is HOLDING to indicate we're preserving a safe output */
                    controller->state = CONTROLLER_STATE_HOLDING;
                } else if (temp >= CONTROLLER_TEMP_EARLY_OFF_THRESHOLD && temp <= CONTROLLER_TEMP_HIGH_THRESHOLD) {
                    /* 47 <= temp <= 48: check if temperature is rising */
                    if (controller->previous_temperature_c != 0) {
                        bool is_rising = controller->last_temperature_c > controller->previous_temperature_c;
                        if (is_rising) {
                            /* Temperature rising: turn off heater early */
                            controller->inlet_open = false;
                            controller->heater_on = false;
                            controller->state = CONTROLLER_STATE_HOLDING;
                        } else {
                            /* Not rising: hold previous safe heater state */
                            controller->state = CONTROLLER_STATE_HOLDING;
                        }
                    } else {
                        /* First time in this band, default to holding */
                        controller->state = CONTROLLER_STATE_HOLDING;
                    }
                } else if (temp > CONTROLLER_TEMP_HIGH_THRESHOLD) {
                    /* temp > 48: close inlet and turn off heater */
                    controller->inlet_open = false;
                    controller->heater_on = false;
                    controller->state = CONTROLLER_STATE_SAFE_IDLE;
                }
            }
        }
        break;

    case CONTROLLER_INPUT_TEMPERATURE:
        /* Update temperature sensor data */
        controller->has_valid_temperature = true;
        controller->previous_temperature_c = controller->last_temperature_c;
        controller->last_temperature_c = input.temperature_c;
        controller->last_temperature_ms = current_ms;

        /* If no valid level yet, stay in safe state */
        if (!controller->has_valid_level) {
            controller_set_safe_idle(controller);
            return output;
        }

        /* Both sensors valid - apply control policy */
        int level = controller->last_level;
        int temp = controller->last_temperature_c;

        /* Check heater safety: if level < 55, keep heater OFF */
        if (level < CONTROLLER_MIN_HEATING_LEVEL) {
            controller->heater_on = false;
            /* Inlet control based on level */
            if (level < CONTROLLER_FILL_LEVEL_THRESHOLD) {
                controller->inlet_open = true;
                /* State is FILLING because inlet is open due to low level */
                controller->state = CONTROLLER_STATE_FILLING;
            } else if (level > CONTROLLER_LEVEL_HIGH_THRESHOLD) {
                controller->inlet_open = false;
                /* State is SAFE_IDLE because level is too high */
                controller->state = CONTROLLER_STATE_SAFE_IDLE;
            } else {
                /* 60 <= level <= 75 - check temperature control */
                if (temp < CONTROLLER_TEMP_LOW_THRESHOLD) {
                    /* Level safe, temp low: close inlet and turn on heater */
                    controller->inlet_open = false;
                    controller->heater_on = true;
                    controller->state = CONTROLLER_STATE_HEATING;
                } else if (temp >= CONTROLLER_TEMP_LOW_THRESHOLD && temp < CONTROLLER_TEMP_EARLY_OFF_THRESHOLD) {
                    /* 45 <= temp < 47: hold previous safe heater state */
                    /* Keep current inlet and heater state */
                    /* State is HOLDING to indicate we're preserving a safe output */
                    controller->state = CONTROLLER_STATE_HOLDING;
                } else if (temp >= CONTROLLER_TEMP_EARLY_OFF_THRESHOLD && temp <= CONTROLLER_TEMP_HIGH_THRESHOLD) {
                    /* 47 <= temp <= 48: check if temperature is rising */
                    if (controller->previous_temperature_c != 0) {
                        bool is_rising = controller->last_temperature_c > controller->previous_temperature_c;
                        if (is_rising) {
                            /* Temperature rising: turn off heater early */
                            controller->inlet_open = false;
                            controller->heater_on = false;
                            controller->state = CONTROLLER_STATE_HOLDING;
                        } else {
                            /* Not rising: hold previous safe heater state */
                            controller->state = CONTROLLER_STATE_HOLDING;
                        }
                    } else {
                        /* First time in this band, default to holding */
                        controller->state = CONTROLLER_STATE_HOLDING;
                    }
                } else if (temp > CONTROLLER_TEMP_HIGH_THRESHOLD) {
                    /* temp > 48: close inlet and turn off heater */
                    controller->inlet_open = false;
                    controller->heater_on = false;
                    controller->state = CONTROLLER_STATE_SAFE_IDLE;
                }
            }
        }
        break;
    }

    output.inlet_open = controller->inlet_open;
    output.heater_on = controller->heater_on;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed =
        (previous_inlet_open != controller->inlet_open) ||
        (previous_heater_on != controller->heater_on) ||
        (previous_state != controller->state);

    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_FILLING:
        return "STATE FILLING";
    case CONTROLLER_STATE_HEATING:
        return "STATE HEATING";
    case CONTROLLER_STATE_HOLDING:
        return "STATE HOLDING";
    case CONTROLLER_STATE_SAFE_IDLE:
